} eval_think_close_info;

typedef struct {
    int cols;
    int rows;
    int left_w;
    int right_x;
    int right_w;
    int body_y;
    int body_h;
    bool active;
    bool enabled;
    const eval_case *cases;
    int ncases;
    eval_status *status;
    char (*guess)[EVAL_ANSWER_MAX];
    int *prompt_tokens;
    int *generated_tokens;
    int active_case;
    int generated;
