3222	/* Decide how one trace case regrades. Only PASSED/FAILED traces were graded by
3223	 * a completed run; STOPPED/SKIPPED/SWITCHED/ERROR cases carry partial or no
3224	 * model output and must be reported as not-graded rather than counted, since
3225	 * grading them inflates the totals and raises spurious "changed" drift. An
3226	 * empty status keeps legacy traces (written before the status line) working. */
3227	static regrade_outcome regrade_case_outcome(const eval_case *tc,
3228	                                            const char *traced_status,
